import{c as i,S as s,j as a,m as e}from"./chunks/framework.Bcm8lc2D.js";const u=JSON.parse('{"title":"大语言模型（LLM）基础知识扫盲","description":"","frontmatter":{"title":"大语言模型（LLM）基础知识扫盲","date":"2026-05-25T00:00:00.000Z","tags":"AI, AI基础, LLM, Token, 上下文窗口","summary":"用通俗语言解释什么是LLM、Token、上下文窗口、Temperature等核心概念，帮你建立对大语言模型的基本认知","author":"ai-helper"},"headers":[],"relativePath":"blog/posts/2026-05-25-大语言模型LLM基础知识扫盲.md","filePath":"blog/posts/2026-05-25-大语言模型LLM基础知识扫盲.md"}'),o={name:"blog/posts/2026-05-25-大语言模型LLM基础知识扫盲.md"};function l(n,t,r,p,h,k){return s(),a("div",null,t[0]||(t[0]=[e(`<h1 id="大语言模型-llm-基础知识扫盲" tabindex="-1">大语言模型（LLM）基础知识扫盲 <a class="header-anchor" href="#大语言模型-llm-基础知识扫盲" aria-label="Permalink to &quot;大语言模型（LLM）基础知识扫盲&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>如果你是一个后端开发、前端开发或者全栈工程师，最近一两年你一定被各种&quot;AI&quot;、&quot;大模型&quot;、&quot;LLM&quot;的新闻刷屏了。但说实话，很多科普文章要么太学术、要么太营销，看完之后你可能还是不太清楚这东西到底是什么、能干什么、不能干什么。</p><p>这篇文章就站在一个&quot;有编程基础但AI知识薄弱的开发者&quot;的角度，把 LLM 最核心的概念讲清楚。</p><h2 id="llm-到底是什么" tabindex="-1">LLM 到底是什么？ <a class="header-anchor" href="#llm-到底是什么" aria-label="Permalink to &quot;LLM 到底是什么？&quot;">​</a></h2><p><strong>LLM（Large Language Model），大语言模型。</strong> 你可以把它理解成一个&quot;超级自动补全器&quot;。</p><p>就像你手机输入法会根据你已打的字猜测下一个字一样，LLM 也是在做类似的事情——根据前面的文本，预测下一个最可能出现的词。只不过它的规模大了几个数量级，训练数据覆盖了互联网上大量的文本，所以它&quot;补全&quot;出来的内容看起来像是一个知识渊博的人在回答问题。</p><p>用一个更具体的类比：</p><ul><li><strong>传统程序</strong>：你写好规则，它按规则执行 → 规则是确定的</li><li><strong>LLM</strong>：你给它一段话，它基于概率生成下一段话 → 输出是有随机性的</li></ul><p>所以 LLM 本质上是一个<strong>概率模型</strong>，不是数据库，也不是搜索引擎。它不&quot;知道&quot;答案，而是&quot;推测&quot;出一个合理的回答。</p><h2 id="token-llm-世界的-货币单位" tabindex="-1">Token：LLM 世界的&quot;货币单位&quot; <a class="header-anchor" href="#token-llm-世界的-货币单位" aria-label="Permalink to &quot;Token：LLM 世界的&quot;货币单位&quot;&quot;">​</a></h2><p>你调用 LLM API 的时候，会看到 <code>token</code> 这个概念。Token 是 LLM 处理文本的最小单位。</p><p><strong>Token 不等于汉字。</strong></p><ul><li>英文中，一个单词可能被拆成 1-3 个 token（如 &quot;unbelievable&quot; → &quot;un&quot; + &quot;believ&quot; + &quot;able&quot;）</li><li>中文中，一个汉字通常是 1-2 个 token</li><li>大致经验值：1 个 token 约等于 0.75 个英文单词，或者 1.5 个中文字符</li></ul><p>Token 为什么重要？因为：</p><ol><li><strong>计费单位</strong>：API 调用按 token 计费，输入和输出分别算</li><li><strong>上下文窗口的度量</strong>：模型一次能处理多少 token 是有限制的</li><li><strong>响应速度</strong>：token 数越多，生成越慢</li></ol><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用 tiktoken 库估算 token 数（GPT 系列）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tiktoken</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">encoder </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tiktoken.encoding_for_model(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gpt-4o&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">text </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;你好，世界！Hello World!&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tokens </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> encoder.encode(text)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;文本长度: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{len</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(text)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">, Token数: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{len</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tokens)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 大约输出: 文本长度: 16, Token数: 6</span></span></code></pre></div><h2 id="上下文窗口-模型的-短期记忆" tabindex="-1">上下文窗口：模型的&quot;短期记忆&quot; <a class="header-anchor" href="#上下文窗口-模型的-短期记忆" aria-label="Permalink to &quot;上下文窗口：模型的&quot;短期记忆&quot;&quot;">​</a></h2><p>上下文窗口（Context Window）是指模型一次能&quot;看到&quot;多少 token 的内容。你可以把它理解为模型的&quot;工作记忆&quot;或&quot;短期记忆&quot;。</p><table tabindex="0"><thead><tr><th>模型</th><th>上下文窗口（约）</th></tr></thead><tbody><tr><td>GPT-4o</td><td>128K tokens</td></tr><tr><td>Claude 3.5 Sonnet</td><td>200K tokens</td></tr><tr><td>Gemini 1.5 Pro</td><td>1M-2M tokens</td></tr><tr><td>DeepSeek-V3</td><td>128K tokens</td></tr><tr><td>通义千问</td><td>128K tokens</td></tr></tbody></table><p><strong>超过上下文窗口的内容，模型是&quot;看不见&quot;的。</strong> 这就像你同时看一本 300 页的书和一本 30 页的书，你对 30 页的内容记忆肯定更清晰。</p><p>对开发者的实际影响：</p><ul><li>如果你的 prompt 太长（比如塞了一整本书的内容），可能超出窗口限制</li><li>超长上下文不代表模型能精准利用每一个细节，它对中间部分的内容关注度往往较低（学术上叫 &quot;Lost in the Middle&quot;）</li><li>在实际应用中，与其把一大堆内容塞进 prompt，不如先做一轮筛选和摘要</li></ul><h2 id="temperature-和-top-p-控制模型的-创造力" tabindex="-1">Temperature 和 Top-P：控制模型的&quot;创造力&quot; <a class="header-anchor" href="#temperature-和-top-p-控制模型的-创造力" aria-label="Permalink to &quot;Temperature 和 Top-P：控制模型的&quot;创造力&quot;&quot;">​</a></h2><p>这两个参数决定了模型输出的随机性。</p><p><strong>Temperature（温度）</strong>：</p><ul><li>范围通常是 0-2，默认值一般是 1</li><li>Temperature 越低，模型越&quot;保守&quot;，倾向于选概率最高的那个词</li><li>Temperature 越高，模型越&quot;放飞自我&quot;，会选一些概率较低但可能更有创意的词</li></ul><p>用类比来说：</p><ul><li>Temperature = 0：像一个严谨的公务员写报告，措辞标准、少有惊喜</li><li>Temperature = 1：像一个正常的聊天，有逻辑但也有一些变化</li><li>Temperature = 1.5：像喝了两杯酒之后聊天，有趣但可能跑偏</li></ul><p><strong>Top-P（核采样）</strong>：</p><ul><li>范围 0-1，默认值一般是 1</li><li>Top-P = 0.1：只从概率最高的前 10% 的候选词中选择</li><li>Top-P = 1：从所有候选词中选择</li></ul><p><strong>开发者怎么选？</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>建议设置</th></tr></thead><tbody><tr><td>代码生成、数据提取、分类任务</td><td>Temperature = 0 或很低</td></tr><tr><td>正常对话、邮件撰写</td><td>Temperature = 0.7</td></tr><tr><td>创意写作、头脑风暴</td><td>Temperature = 1.0+</td></tr></tbody></table><p>一般建议：<strong>调一个就行</strong>，不要同时调 Temperature 和 Top-P，容易互相干扰。</p><h2 id="llm-能干什么-不能干什么" tabindex="-1">LLM 能干什么？不能干什么？ <a class="header-anchor" href="#llm-能干什么-不能干什么" aria-label="Permalink to &quot;LLM 能干什么？不能干什么？&quot;">​</a></h2><p>作为开发者，你需要清楚 LLM 的能力边界：</p><p><strong>LLM 擅长的事：</strong></p><ul><li>文本理解与生成（写文章、翻译、摘要）</li><li>代码生成与解释（写函数、debug、代码审查）</li><li>逻辑推理（简单的数学、因果推断）</li><li>格式转换（JSON ↔ XML、Markdown ↔ HTML）</li><li>知识问答（在训练数据范围内）</li></ul><p><strong>LLM 不擅长或做不到的事：</strong></p><ul><li><strong>精确计算</strong>：它不是计算器，做复杂算术会出错</li><li><strong>实时信息</strong>：它有训练数据截止日期，不知道&quot;今天&quot;发生了什么</li><li><strong>保持一致性</strong>：同样的问题问两次，可能给出不同的答案</li><li><strong>严格遵循规则</strong>：复杂的业务规则很难通过 prompt 完全约束</li><li><strong>专业领域深度知识</strong>：在非常垂直的领域可能产生&quot;一本正经地胡说八道&quot;（即幻觉 Hallucination）</li></ul><h2 id="一些给开发者的实用建议" tabindex="-1">一些给开发者的实用建议 <a class="header-anchor" href="#一些给开发者的实用建议" aria-label="Permalink to &quot;一些给开发者的实用建议&quot;">​</a></h2><ol><li><p><strong>不要把 LLM 当万能工具</strong>。它是一个强大的文本处理引擎，但不是数据库、不是搜索引擎、不是计算器。该用传统工具的地方就用传统工具。</p></li><li><p><strong>Prompt 是你的新&quot;代码&quot;</strong>。和 LLM 交互的核心方式就是写好 prompt。一个好的 prompt 和一个差的 prompt，结果差距可能是天壤之别。</p></li><li><p><strong>理解概率性本质</strong>。不要期望 LLM 的输出 100% 准确。在你的应用中需要有兜底方案和校验机制。</p></li><li><p><strong>关注 token 消耗</strong>。在生产环境中，不必要的 token 消耗就是真金白银。学会精简 prompt、合理设置 max_tokens。</p></li></ol><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>LLM 本质上是一个超大规模的文本概率模型，通过 Token 处理文本，受上下文窗口限制，通过 Temperature 等参数控制输出风格。它在文本理解和生成方面非常强大，但在精确计算、实时信息、严格一致性方面有明显短板。理解这些基本概念，是你在实际项目中用好 AI 的第一步。</p><p>下一篇我们会对比主流 AI 模型的各自特长，帮你选到最合适的那一个。</p>`,45)]))}const g=i(o,[["render",l]]);export{u as __pageData,g as default};
